  const dep=r["Deployed At"], retro=r["Retro Approval Date"];
  let gap=null;
  if(dep&&retro){gap=helpers.businessDaysBetween(helpers.parseDate(dep),helpers.parseDate(retro));}
  return {id:r["Change ID"],sev:r.Severity,dep,retro,by:r["Approved By"],gap,flag:(retro==null||r["Approved By"]==null)?"MISSING":(gap>5?"LATE":"ok")};
});
return out;

